import subprocess

def install_dependencies():
    # Use pip to install dependencies from requirements.txt
    subprocess.run(["pip", "install", "-r", "requirements.txt"])
    
def update_dependency(name, version):
    # Update a specific dependency in the requirements.txt file
    with open("requirements.txt", "r") as file:
        lines = file.readlines()
    
    with open("requirements.txt", "w") as file:
        for line in lines:
            if line.startswith(name + '=='):
                file.write(f"{name}=={version}\n")
            else:
                file.write(line)
                
def generate_requirements():
    # Use pip to create a new requirements.txt file based on the current environment
    subprocess.run(["pip", "freeze", ">", "requirements.txt"])
    
